/* TrainingCard.jsx */
import React from 'react';
import './TrainingCard.css';

function StarRating({ rating }) {
  const r = rating || 0;
  return (
    <div className="tcard__stars">
      {[1,2,3,4,5].map(i => (
        <span key={i} style={{
          color: i <= Math.round(r) ? '#FCD34D' : 'var(--text-muted)',
          fontSize: '0.9rem',
        }}>★</span>
      ))}
      <span style={{ fontWeight: 700, color: '#FCD34D', marginLeft: 4, fontSize: '0.85rem' }}>
        {r.toFixed(1)}
      </span>
    </div>
  );
}

// Category → Unsplash cover image
const CATEGORY_IMAGES = {
  'Engineering':   'https://images.unsplash.com/photo-1555066931-4365d14bab8c?w=600&q=80',
  'Data Science':  'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=600&q=80',
  'Design':        'https://images.unsplash.com/photo-1626785774573-4b799315345d?w=600&q=80',
  'DevOps':        'https://images.unsplash.com/photo-1667372393119-3d4c48d07fc9?w=600&q=80',
  'Marketing':     'https://images.unsplash.com/photo-1533750349088-cd871a92f312?w=600&q=80',
  'Finance':       'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=600&q=80',
  'Product':       'https://images.unsplash.com/photo-1507238691740-187a5b1d37b8?w=600&q=80',
  'Web3':          'https://images.unsplash.com/photo-1639762681485-074b7f938ba0?w=600&q=80',
  'default':       'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=600&q=80',
};

// Category → gradient overlay color
const CATEGORY_GRADIENT = {
  'Engineering':  'rgba(196,181,253,0.85)',
  'Data Science': 'rgba(134,239,172,0.85)',
  'Design':       'rgba(252,165,165,0.85)',
  'DevOps':       'rgba(103,232,249,0.85)',
  'Marketing':    'rgba(252,211,77,0.85)',
  'Finance':      'rgba(134,239,172,0.85)',
  'Product':      'rgba(196,181,253,0.85)',
  'default':      'rgba(196,181,253,0.85)',
};

export default function TrainingCard({ training, onOpenModal }) {
  const {
    title        = 'Untitled Course',
    category     = 'General',
    tagColor     = 'lavender',
    level        = 'Beginner',
    description  = '',
    duration     = '',
    price        = 0,
    enrolled     = 0,
    rating       = 0,
    reviews      = 0,
    lessons,
    chapters,
    tags,
    provider,
    featured,
  } = training || {};

  const color       = tagColor || 'lavender';
  const displayTags = Array.isArray(tags) && tags.length > 0 ? tags.slice(0, 2) : [category];
  const imgSrc      = CATEGORY_IMAGES[category] || CATEGORY_IMAGES['default'];
  const gradColor   = CATEGORY_GRADIENT[category] || CATEGORY_GRADIENT['default'];

  return (
    <div className="tcard" onClick={() => onOpenModal && onOpenModal(training)}
      style={{ cursor: 'pointer' }}>

      {/* ── COVER IMAGE THUMBNAIL ── */}
      <div className="tcard__thumb">
        {/* Real photo */}
        <img
          src={imgSrc}
          alt={title}
          className="tcard__thumb-img"
          onError={e => { e.target.style.display = 'none'; }}
        />
        {/* Gradient overlay */}
        <div className="tcard__thumb-overlay-img" />

        {/* Top badges */}
        <div className="tcard__thumb-top">
          <span className={`tcard__cat-badge tcard__cat-badge--${color}`}>{category}</span>
          {featured && <span className="tcard__popular-badge">⚡ Popular</span>}
        </div>

        {/* Bottom level badge */}
        <div className="tcard__thumb-bottom">
          <span className="tcard__level-badge">{level}</span>
          <span className="tcard__play-btn">▶ Preview</span>
        </div>
      </div>

      {/* ── CARD BODY ── */}
      <div className="tcard__body">
        <h4 className="tcard__title">{title}</h4>

        {(provider || category) && (
          <p className="tcard__provider">{provider || category}</p>
        )}

        {description && (
          <p className="tcard__desc">
            {description.length > 85 ? description.slice(0, 85) + '…' : description}
          </p>
        )}

        {/* Stats row */}
        <div className="tcard__meta-row">
          {duration && (
            <span className="tcard__meta-item">
              <span className="tcard__meta-icon">⏱</span>{duration}
            </span>
          )}
          {lessons > 0 && (
            <span className="tcard__meta-item">
              <span className="tcard__meta-icon">📚</span>{lessons} lessons
            </span>
          )}
          {chapters > 0 && (
            <span className="tcard__meta-item">
              <span className="tcard__meta-icon">📂</span>{chapters} chapters
            </span>
          )}
        </div>

        <div className="tcard__rating-row">
          <StarRating rating={rating} />
          <span className="tcard__reviews">({(reviews || 0).toLocaleString()})</span>
        </div>

        {/* Footer */}
        <div className="tcard__footer">
          <div className="tcard__price-wrap">
            {price === 0
              ? <span className="tcard__free">🆓 Free</span>
              : <span className="tcard__price">₹{price.toLocaleString()}</span>
            }
            <span className="tcard__enrolled-count">
              👥 {enrolled >= 1000 ? `${(enrolled/1000).toFixed(1)}k` : enrolled}
            </span>
          </div>
          <span className="tcard__cta">View Course →</span>
        </div>
      </div>
    </div>
  );
}
